using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve the EF8 property name so existing 500K documents remain readable
            // and direct SQL queries referencing c.Discriminator keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "EntityType|Key" to just "Key".
            // Preserve the EF8 format so existing documents with "Product|123" ids are found.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonPropertyName("id")
                  .HasValueGenerator<ProductIdValueGenerator>();
        });
    }
}

// Preserves the EF8 "Product|{key}" id format for new documents
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductIdValueGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
    {
        var id = entry.Property("Id").CurrentValue;
        return $"Product|{id}";
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

